//! # Table Rendering
//!
//! This module provides markdown table rendering with lipgloss styling support.
//!
//! ## Quick Start
//!
//! ```rust
//! use glamour::{Glamour, TableStyle};
//!
//! let markdown = r#"
//! | Name  | Age | City     |
//! |:------|:---:|----------|
//! | Alice | 30  | New York |
//! | Bob   | 25  | London   |
//! "#;
//!
//! let glamour = Glamour::new();
//! let rendered = glamour.render(markdown)?;
//! println!("{}", rendered);
//! ```
//!
//! ## Table Alignment
//!
//! Markdown table alignment is specified in the separator row:
//!
//! | Syntax | Alignment |
//! |--------|-----------|
//! | `:---` | Left      |
//! | `:---:` | Center   |
//! | `---:` | Right     |
//! | `---`  | Default (Left) |
//!
//! ## Styling
//!
//! Tables can be styled using the [`TableStyle`] configuration:
//!
//! ```rust
//! use glamour::{Glamour, TableStyle, TableBorder};
//!
//! let style = TableStyle {
//!     border: TableBorder::Rounded,
//!     header_bold: true,
//!     ..Default::default()
//! };
//!
//! let glamour = Glamour::with_style(style);
//! ```

/// Renders a markdown table to a styled string.
///
/// # Arguments
///
/// * `table` - The parsed table structure
/// * `style` - Styling configuration for the table
///
/// # Returns
///
/// A string containing the rendered table with ANSI escape codes.
///
/// # Example
///
/// ```rust
/// let table = ParsedTable {
///     alignments: vec![Alignment::Left, Alignment::Center],
///     header: vec![
///         TableCell::new("Name"),
///         TableCell::new("Score"),
///     ],
///     rows: vec![
///         vec![TableCell::new("Alice"), TableCell::new("95")],
///         vec![TableCell::new("Bob"), TableCell::new("87")],
///     ],
/// };
///
/// let output = render_table(&table, &TableStyle::default());
/// ```
