            Cmd::message(2),
            Cmd::message(3),
        ];
        let batch = Cmd::batch(cmds);
        let results: Vec<_> = batch.execute_all().await;
        assert_eq!(results, vec![1, 2, 3]);
    }

    #[tokio::test]
    async fn test_cmd_sequence_orders_correctly() {
        let seq = Cmd::sequence(vec![
            Cmd::message("first"),
            Cmd::message("second"),
        ]);
        // Should execute in order
        let mut results = vec![];
        for msg in seq.execute_sequential().await {
            results.push(msg);
        }
        assert_eq!(results, vec!["first", "second"]);
    }
}
